class DocumentLoader:
    """Loads and chunks documents from various file formats."""

    SUPPORTED_EXTENSIONS = {".txt", ".md", ".json", ".csv", ".py", ".html", ".pdf"}

    def __init__(self, chunk_size: int = 500, chunk_overlap: int = 100):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def load_directory(self, directory_path: str) -> List[Dict]:
        """Load all supported documents from a directory recursively."""
        documents = []
        dir_path = Path(directory_path)

        if not dir_path.exists():
            raise FileNotFoundError(f"Directory not found: {directory_path}")

        for file_path in dir_path.rglob("*"):
            if file_path.is_file() and file_path.suffix.lower() in self.SUPPORTED_EXTENSIONS:
                try:
                    docs = self.load_file(str(file_path))
                    documents.extend(docs)
                    print(f"  Loaded: {file_path} ({len(docs)} chunks)")
                except Exception as e:
                    print(f"  Error loading {file_path}: {e}")

        return documents

    def load_file(self, file_path: str) -> List[Dict]:
        """Load a single file and return chunked documents."""
        path = Path(file_path)
        extension = path.suffix.lower()

        if extension == ".json":
            content = self._load_json(file_path)
        elif extension == ".csv":
            content = self._load_csv(file_path)
        elif extension == ".pdf":
            content = self._load_pdf(file_path)
        else:
            content = self._load_text(file_path)

        chunks = self._chunk_text(content)

        documents = []
        for i, chunk in enumerate(chunks):
            doc_id = hashlib.md5(f"{file_path}_{i}".encode()).hexdigest()
            documents.append({
                "id": doc_id,
                "content": chunk,
                "metadata": {
                    "source": str(file_path),
                    "filename": path.name,
                    "chunk_index": i,
                    "total_chunks": len(chunks),
                    "file_type": extension,
                }
            })

        return documents

    def _load_text(self, file_path: str) -> str:
        with open(file_path, "r", encoding="utf-8", errors="ignore") as f:
            return f.read()

    def _load_json(self, file_path: str) -> str:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return json.dumps(data, indent=2)

    def _load_csv(self, file_path: str) -> str:
        import csv
        rows = []
        with open(file_path, "r", encoding="utf-8", errors="ignore") as f:
            reader = csv.reader(f)
            for row in reader:
                rows.append(" | ".join(row))
        return "\n".join(rows)

    def _load_pdf(self, file_path: str) -> str:
        try:
            import PyPDF2
            text_parts = []
            with open(file_path, "rb") as f:
                reader = PyPDF2.PdfReader(f)
                for page in reader.pages:
                    text = page.extract_text()
                    if text:
                        text_parts.append(text)
            return "\n".join(text_parts)
        except ImportError:
            print("  PyPDF2 not installed. Skipping PDF. Install with: pip install PyPDF2")
            return ""

    def _chunk_text(self, text: str) -> List[str]:
        """Split text into overlapping chunks."""
        if not text.strip():
            return []

        words = text.split()
        chunks = []
        start = 0

        while start < len(words):
            end = start + self.chunk_size
            chunk = " ".join(words[start:end])
            if chunk.strip():
                chunks.append(chunk.strip())
            start += self.chunk_size - self.chunk_overlap

        return chunks if chunks else [text.strip()]


class EmbeddingModel:
    """Handles text embedding using sentence-transformers."""

    def __init__(self, model_name: str = "all-MiniLM-L6-v2"):
        print(f"Loading embedding model: {model_name}...")
        self.model = SentenceTransformer(model_name)
        print("Embedding model loaded.")

    def embed(self, texts: List[str]) -> List[List[float]]:
        """Generate embeddings for a list of texts."""
        embeddings = self.model.encode(texts, show_progress_bar=False)
        return embeddings.tolist()

    def embed_single(self, text: str) -> List[float]:
        """Generate embedding for a single text."""
        return self.embed([text])[0]


class VectorStore:
    """ChromaDB-based vector store for document storage and retrieval."""

    def __init__(self, collection_name: str = "company_knowledge_base",
                 persist_directory: str = "./chroma_db"):
        self.persist_directory = persist_directory
        self.client = chromadb.Client(Settings(
            chroma_db_impl="duckdb+parquet",
            persist_directory=persist_directory,
            anonymized_telemetry=False,
        )) if hasattr(chromadb, 'Client') else chromadb.PersistentClient(path=persist_directory)

        self.collection = self.client.get_or_create_collection(
            name=collection_name,
            metadata={"hnsw:space": "cosine"}
        )
        print(f"Vector store initialized. Collection '{collection_name}' has {self.collection.count()} documents.")

    def add_documents(self, documents: List[Dict], embeddings: List[List[float]]):
        """Add documents with their embeddings to the vector store."""
        if not documents:
            return

        batch_size = 100
        for i in range(0, len(documents), batch_size):
            batch_docs = documents[i:i + batch_size]
            batch_embeddings = embeddings[i:i + batch_size]

            ids = [doc["id"] for doc in batch_docs]
            contents = [doc["content"] for doc in batch_docs]
            metadatas = [doc["metadata"] for doc in batch_docs]

            self.collection.upsert(
                ids=ids,
                documents=contents,
                embeddings=batch_embeddings,
                metadatas=metadatas,
            )

        print(f"Added/updated {len(documents)} documents. Total: {self.collection.count()}")

    def search(self, query_embedding: List[float], top_k: int = 5) -> List[Dict]:
        """Search for similar documents using query embedding."""
        results = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=min(top_k, self.collection.count()),
            include=["documents", "metadatas", "distances"]
        )

        retrieved = []
        if results and results["documents"] and results["documents"][0]:
            for i in range(len(results["documents"][0])):
                retrieved.append({
                    "content": results["documents"][0][i],
                    "metadata": results["metadatas"][0][i] if results["metadatas"] else {},
                    "distance": results["distances"][0][i] if results["distances"] else None,
                    "relevance_score": 1 - (results["distances"][0][i] if results["distances"] else 0),
                })

        return retrieved

    def get_stats(self) -> Dict:
        """Get collection statistics."""
        return {
            "total_documents": self.collection.count(),
            "persist_directory": self.persist_directory,
        }

    def clear(self):
        """Clear all documents from the collection."""
        if self.collection.count() > 0:
            all_ids = self.collection.get()["ids"]
            if all_ids:
                self.collection.delete(ids=all_ids)
        print("Vector store cleared.")


class LLMClient:
    """Client for interacting with OpenAI-compatible LLM APIs."""

    def __init__(self, api_key: Optional[str] = None, model: str = "gpt-3.5-turbo",
                 base_url: Optional[str] = None, temperature: float = 0.3):
        self.api_key = api_key or os.getenv("OPENAI_API_KEY")
        self.model = model
        self.temperature = temperature

        if not self.api_key:
            print("WARNING: No OpenAI API key found. Set OPENAI_API_KEY environment variable.")
            print("The system will work in retrieval-only mode (no LLM generation).")
            self.client = None
        else:
            kwargs = {"api_key": self.api_key}
            if base_url:
                kwargs["base_url"] = base_url
            self.client = openai.OpenAI(**kwargs)

    def generate(self, prompt: str, system_prompt: str = "") -> str:
        """Generate a response from the LLM."""
        if not self.client:
            return "[LLM not available - showing retrieved context only]"

        messages = []
        if system_prompt:
            messages.append({"role": "system", "content": system_prompt})
        messages.append({"role": "user", "content": prompt})

        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                temperature=self.temperature,
                max_tokens=1500,
            )
            return response.choices[0].message.content
        except Exception as e:
            return f"[LLM Error: {e}]"


class RAGSystem:
    """Main RAG system that orchestrates document loading, retrieval, and generation."""

    SYSTEM_PROMPT = """You are a helpful internal knowledge base assistant for our company. 
Your role is to answer questions based on the provided context from company documents.

Guidelines:
- Answer questions accurately based ONLY on the provided context.
- If the context doesn't contain enough information to answer, say so clearly.
- Cite the source documents when possible (mention filenames).
- Be concise but thorough.
- If multiple documents provide relevant information, synthesize them into a coherent answer.
- Do not make up information that is not in the provided context."""

    def __init__(self, 
                 collection_name: str = "company_knowledge_base",
                 persist_directory: str = "./chroma_db",
                 embedding_model_name: str = "all-MiniLM-L6-v2",
                 llm_model: str = "gpt-3.5-turbo",
                 openai_api_key: Optional[str] = None,
                 openai_base_url: Optional[str] = None,
                 chunk_size: int = 500,
                 chunk_overlap: int = 100,
                 top_k: int = 5):

        self.top_k = top_k
        self.document_loader = DocumentLoader(chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        self.embedding_model = EmbeddingModel(model_name=embedding_model_name)
        self.vector_store = VectorStore(
            collection_name=collection_name,
            persist_directory=persist_directory
        )
        self.llm_client = LLMClient(
            api_key=openai_api_key,
            model=llm_model,
            base_url=openai_base_url,
        )
        self.conversation_history: List[Dict] = []

    def ingest_documents(self, source_path: str):
        """Load documents from a file or directory into the vector store."""
        print(f"\n{'='*60}")
        print(f"Ingesting documents from: {source_path}")
        print(f"{'='*60}")

        path = Path(source_path)
        if path.is_directory():
            documents = self.document_loader.load_directory(source_path)
        elif path.is_file():
            documents = self.document_loader.load_file(source_path)
        else:
            raise FileNotFoundError(f"Path not found: {source_path}")

        if not documents:
            print("No documents found to ingest.")
            return

        print(f"\nGenerating embeddings for {len(documents)} chunks...")
        contents = [doc["content"] for doc in documents]

        batch_size = 64
        all_embeddings = []
        for i in range(0, len(contents), batch_size):
            batch = contents[i:i + batch_size]
            batch_embeddings = self.embedding_model.embed(batch)
            all_embeddings.extend(batch_embeddings)
            print(f"  Embedded {min(i + batch_size, len(contents))}/{len(contents)} chunks")

        print("Storing in vector database...")
        self.vector_store.add_documents(documents, all_embeddings)
        print(f"Ingestion complete!\n")

    def retrieve(self, query: str, top_k: Optional[int] = None) -> List[Dict]:
        """Retrieve relevant documents for a query."""
        k = top_k or self.top_k
        query_embedding = self.embedding_model.embed_single(query)
        results = self.vector_store.search(query_embedding, top_k=k)
        return results

    def _build_context(self, retrieved_docs: List[Dict]) -> str:
        """Build context string from retrieved documents."""
        if not retrieved_docs:
            return "No relevant documents found in the knowledge base."

        context_parts = []
        for i, doc in enumerate(retrieved_docs, 1):
            source = doc["metadata"].get("filename", "Unknown")
            score = doc.get("relevance_score", 0)
            chunk_info = ""
            if "chunk_index" in doc["metadata"]:
                chunk_info = f" (chunk {doc['metadata']['chunk_index'] + 1}/{doc['metadata']['total_chunks']})"

            context_parts.append(
                f"--- Document {i} [Source: {source}{chunk_info}, Relevance: {score:.2f}] ---\n"
                f"{doc['content']}\n"
            )

        return "\n".join(context_parts)

    def _build_prompt(self, query: str, context: str) -> str:
        """Build the full prompt with context and query."""
        prompt = f"""Based on the following retrieved documents from our internal knowledge base, please answer the user's question.

=== RETRIEVED DOCUMENTS ===
{context}
=== END OF DOCUMENTS ===

User Question: {query}

Please provide a comprehensive answer based on the above documents. If the documents don't contain sufficient information to answer the question, clearly state that."""

        return prompt

    def query(self, user_query: str, top_k: Optional[int] = None, 
              show_sources: bool = True, show_context: bool = False) -> Dict:
        """Process a user query through the full RAG pipeline."""
        # Step 1: Retrieve relevant documents
        retrieved_docs = self.retrieve(user_query, top_k=top_k)

        # Step 2: Build context from ALL retrieved documents
        context = self._build_context(retrieved_docs)

        # Step 3: Build prompt
        prompt = self._build_prompt(user_query, context)

        # Step 4: Generate response
        response = self.llm_client.generate(prompt, system_prompt=self.SYSTEM_PROMPT)

        # Step 5: Build result
        result = {
            "query": user_query,
            "answer": response,
            "num_documents_retrieved": len(retrieved_docs),
            "sources": [],
        }

        if show_sources:
            for doc in retrieved_docs:
                result["sources"].append({
                    "filename": doc["metadata"].get("filename", "Unknown"),
                    "source_path": doc["metadata"].get("source", "Unknown"),
                    "relevance_score": round(doc.get("relevance_score", 0), 4),
                    "chunk_index": doc["metadata"].get("chunk_index", 0),
                })

        if show_context:
            result["context"] = context
            result["full_prompt"] = prompt

        # Store in conversation history
        self.conversation_history.append({
            "query": user_query,
            "answer": response,
            "sources": result["sources"],
        })

        return result

    def get_stats(self) -> Dict:
        """Get system statistics."""
        vs_stats = self.vector_store.get_stats()
        return {
            "vector_store": vs_stats,
            "conversation_history_length": len(self.conversation_history),
            "llm_model": self.llm_client.model,
            "llm_available": self.llm_client.client is not None,
            "top_k": self.top_k,
        }

    def clear_knowledge_base(self):
        """Clear all documents from the knowledge base."""
        self.vector_store.clear()
        print("Knowledge base cleared.")

    def clear_history(self):
        """Clear conversation history."""
        self.conversation_history = []
        print("Conversation history cleared.")


def format_response(result: Dict) -> str:
    """Format a query result for display."""
    output = []
    output.append(f"\n{'='*60}")
    output.append(f"Question: {result['query']}")
    output.append(f"{'='*60}")
    output.append(f"\nAnswer:\n{result['answer']}")

    if result.get("sources"):
        output.append(f"\n{'─'*40}")
        output.append(f"Sources ({result['num_documents_retrieved']} documents retrieved):")
        for i, source in enumerate(result["sources"], 1):
            output.append(
                f"  {i}. {source['filename']} "
                f"(chunk {source['chunk_index']}, "
                f"relevance: {source['relevance_score']:.2f})"
            )

    output.append(f"{'='*60}\n")
    return "\n".join(output)


