def interactive_chat(rag: RAGSystem):
    """Run an interactive chat session."""
    print("\n" + "=" * 60)
    print("  Acme Corporation Knowledge Base Chatbot")
    print("  Type 'quit' to exit, 'stats' for system info,")
    print("  'history' for conversation history, 'clear' to reset")
    print("=" * 60 + "\n")

    while True:
        try:
            user_input = input("You: ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\nGoodbye!")
            break

        if not user_input:
            continue

        if user_input.lower() == "quit":
            print("Goodbye!")
            break
        elif user_input.lower() == "stats":
            stats = rag.get_stats()
            print(f"\nSystem Stats:")
            print(f"  Documents in KB: {stats['vector_store']['total_documents']}")
            print(f"  LLM Model: {stats['llm_model']}")
            print(f"  LLM Available: {stats['llm_available']}")
            print(f"  Conversation Length: {stats['conversation_history_length']}")
            print(f"  Top-K Retrieval: {stats['top_k']}\n")
            continue
        elif user_input.lower() == "history":
            if not rag.conversation_history:
                print("\nNo conversation history yet.\n")
            else:
                for i, entry in enumerate(rag.conversation_history, 1):
                    print(f"\n--- Turn {i} ---")
                    print(f"Q: {entry['query']}")
                    print(f"A: {entry['answer'][:200]}...")
            print()
            continue
        elif user_input.lower() == "clear":
            rag.clear_history()
            continue

        # Process query
        result = rag.query(user_input, show_sources=True)
        print(format_response(result))


def main():
    """Main entry point for the RAG system."""
    import argparse

    parser = argparse.ArgumentParser(description="Internal Knowledge Base RAG Chatbot")
    parser.add_argument("--docs-dir", type=str, default="./sample_docs",
                        help="Directory containing company documents")
    parser.add_argument("--create-samples", action="store_true",
                        help="Create sample documents for testing")
    parser.add_argument("--db-dir", type=str, default="./chroma_db",
                        help="Directory for vector database persistence")
    parser.add_argument("--collection", type=str, default="company_knowledge_base",
                        help="Name of the vector store collection")
    parser.add_argument("--model", type=str, default="gpt-3.5-turbo",
                        help="LLM model to use")
    parser.add_argument("--embedding-model", type=str, default="all-MiniLM-L6-v2",
                        help="Sentence transformer model for embeddings")
    parser.add_argument("--top-k", type=int, default=5,
                        help="Number of documents to retrieve")
    parser.add_argument("--chunk-size", type=int, default=500,
                        help="Document chunk size in words")
    parser.add_argument("--chunk-overlap", type=int, default=100,
                        help="Overlap between chunks in words")
    parser.add_argument("--api-key", type=str, default=None,
                        help="OpenAI API key (or set OPENAI_API_KEY env var)")
    parser.add_argument("--base-url", type=str, default=None,
                        help="Custom OpenAI-compatible API base URL")
    parser.add_argument("--query", type=str, default=None,
                        help="Single query mode (non-interactive)")
    parser.add_argument("--clear-db", action="store_true",
                        help="Clear the vector database before ingesting")
    parser.add_argument("--skip-ingest", action="store_true",
                        help="Skip document ingestion (use existing DB)")

    args = parser.parse_args()

    # Create sample documents if requested
    if args.create_samples:
        create_sample_documents(args.docs_dir)

    # Initialize RAG system
    print("\nInitializing RAG system...")
    rag = RAGSystem(
        collection_name=args.collection,
        persist_directory=args.db_dir,
        embedding_model_name=args.embedding_model,
        llm_model=args.model,
        openai_api_key=args.api_key,
        openai_base_url=args.base_url,
        chunk_size=args.chunk_size,
        chunk_overlap=args.chunk_overlap,
        top_k=args.top_k,
    )

    # Clear database if requested
    if args.clear_db:
        rag.clear_knowledge_base()

    # Ingest documents
    if not args.skip_ingest:
        docs_path = Path(args.docs_dir)
        if docs_path.exists():
            rag.ingest_documents(args.docs_dir)
        else:
            print(f"\nDocuments directory '{args.docs_dir}' not found.")
            print("Use --create-samples to generate sample documents, or specify --docs-dir")
            if rag.vector_store.get_stats()["total_documents"] == 0:
                print("No documents in database. Creating samples...")
                create_sample_documents(args.docs_dir)
                rag.ingest_documents(args.docs_dir)

    # Print stats
    stats = rag.get_stats()
    print(f"\nSystem ready!")
    print(f"  Documents in knowledge base: {stats['vector_store']['total_documents']}")
    print(f"  LLM model: {stats['llm_model']}")
    print(f"  LLM available: {stats['llm_available']}")

    # Single query or interactive mode
    if args.query:
        result = rag.query(args.query, show_sources=True)
        print(format_response(result))
    else:
        interactive_chat(rag)


if __name__ == "__main__":
    main()